"""
mkt-christ — Leviticus 19–21
Chapters covered: 19 (36 new verses; v18 already exists), 20 (27 verses), 21 (24 verses)
Run: python3 scripts/zc-christ-leviticus-19-21.py

Key typological threads:
  Ch 19 (Holiness Code): every law reflects YHWH's character embodied in Christ; 1 Pet 1:15-16 quotes Lev 19:2
  Ch 20 (Apostasy/sexual purity penalties): Christ bears the covenant curse; clean/unclean distinction abolished
  Ch 21 (Priestly holiness): Levitical high priest's special standards are the detailed type of Christ's unique perfection (Heb 7:26)
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

CHRIST = {
  "19": {
    "1": "<p>A literary frame: the formula 'YHWH spoke to Moses, saying' opens the Holiness Code (chs. 17-26), the dense heart of Leviticus. Every commandment that follows is YHWH's direct speech — the law is not a human ethical system but the expression of the divine character. Christ as the eternal Word (John 1:1) is the personal embodiment of that character: 'the law was given through Moses; grace and truth came through Jesus Christ' (John 1:17). The Holiness Code's 'I am YHWH' refrain (occurring ~15 times in ch. 19 alone) grounds every obligation in the divine self-disclosure that reaches its fullness in the incarnate Son.</p>",
    "2": "<p>A direct quotation: 'You shall be holy, for I YHWH your God am holy.' This is the Holiness Code's governing mandate, and 1 Peter 1:15-16 quotes it directly as the standard for the new covenant community: 'as he who called you is holy, you also be holy in all your conduct.' The ground of the command shifts in 1 Peter: it is the Father who calls, but the means is 'the precious blood of Christ, a lamb without blemish or spot' (1 Pet 1:19). Christ himself is YHWH's holiness made visible — 'holy, innocent, unstained, separated from sinners, and exalted above the heavens' (Heb 7:26); his people are holy by union with him.</p>",
    "3": "<p>A shadow: 'Every one of you shall revere his mother and his father, and keep my sabbaths.' Christ himself lived this commandment — twelve years old in the temple yet returning to Nazareth to be subject to Mary and Joseph (Luke 2:51). Yet he also reorders the honor-command in light of ultimate allegiance: 'Whoever loves father or mother more than me is not worthy of me' (Matt 10:37). In Christ the fifth commandment reaches its telos — not the abolition of family honor but its relativization within the kingdom family, where the deepest bond is to the Father and to brothers and sisters in Christ.</p>",
    "4": "<p>A shadow: 'Do not turn to idols or make for yourselves cast metal images of gods.' Christ is 'the image of the invisible God' (Col 1:15) — the one in whom humanity can truly see God without distortion. The prohibition of cast images is the negative space pointing toward the positive reality: the invisible God, unable to be represented in wood or metal, chose to represent himself in the flesh of the Son. 'Whoever has seen me has seen the Father' (John 14:9). The idol-prohibition is the shadow of the incarnation — no human-made image will suffice; only the image God himself made in his Son.</p>",
    "5": "<p>A shadow: the fellowship offering regulations open with the requirement that the sacrifice be offered 'for your acceptance' (<em>lirtsonchem</em>) — offered in the way that will be pleasing to YHWH. Christ's offering is the perfect fulfillment: 'he gave himself up for us, a fragrant offering and sacrifice to God' (Eph 5:2). The phrase 'fragrant aroma' (<em>reyach nichoach</em>) applied to the fellowship offering becomes Paul's description of Christ's death — the self-offering that is maximally pleasing to the Father, the sacrifice YHWH accepts in the fullest sense.</p>",
    "6": "<p>A shadow: flesh left from the fellowship offering past the second day 'shall be burned with fire; it is tainted (<em>pigul</em>).' The time-limit on eating the sacrifice means the celebration of restored fellowship has its appointed season — it cannot be stored up indefinitely. Christ's resurrection breaks the decay-pattern: 'you will not allow your Holy One to see corruption' (Ps 16:10; Acts 2:27). The fellowship meal in Christ is not time-limited; his body does not decay, and the eucharistic feast he inaugurates will find its fullness at the messianic banquet in the age to come.</p>",
    "7": "<p>A shadow: the tainted offering eaten on the third day shall not be accepted. The number three echoes in the resurrection narrative: 'after three days he will rise' (Matt 27:63). The rejected offering that is eaten beyond its proper time is not accepted — by contrast, Christ's offering, consumed and completed within the proper time (he rose on the third day, not after), is maximally accepted. The sacrifice that fulfilled its purpose in its proper moment is the antithesis of the <em>pigul</em> — the offering YHWH accepted and raised.</p>",
    "8": "<p>A shadow: eating the tainted offering means 'that person shall bear his iniquity.' The phrase <em>nasa avon</em> (bear iniquity) is the same language used of the suffering servant: 'he bore the sin of many' (Isa 53:12). What the offerer incurs by mishandling the sacrifice, Christ incurred on behalf of all who deserved exclusion — he bore the iniquity that the covenant system threatened to lay on violators, taking it onto himself so that those who come to him 'will certainly not be cast out' (John 6:37).</p>",
    "9": "<p>A shadow: 'When you reap the harvest of your land, you shall not reap your field to the very edge, and you shall not gather the gleanings after your harvest.' The gleaning law (Lev 19:9-10) is the legal provision for the poor and the alien — deliberate incompleteness as an act of structured generosity. Ruth gleans in Boaz's field under this provision (Ruth 2:2-3), and Boaz's generosity beyond the legal minimum prefigures Christ. Jesus feeds five thousand in the wilderness (John 6:1-14) — abundance with leftovers — and calls the church to share its resources so that 'there was not a needy person among them' (Acts 4:34).</p>",
    "10": "<p>A shadow: 'You shall not strip your vineyard bare, neither shall you gather the fallen grapes of your vineyard. You shall leave them for the poor and for the sojourner.' The vineyard-gleaning law sets the scene for Jesus's parable of the vineyard (Matt 21:33-43) — the owner who plants a vineyard and expects fruit from the tenants. The messianic vineyard motif runs from Isaiah 5 through John 15 ('I am the true vine'). Christ is the true vine owner who does not strip the vineyard bare but invites the poor and the alien into the harvest of the kingdom.</p>",
    "11": "<p>A shadow: 'You shall not steal; you shall not deal falsely; you shall not lie to one another.' Christ himself is 'the truth' (John 14:6) — the incarnate anti-lie, the one in whom there is no falsehood (1 Pet 2:22: 'no deceit was found in his mouth'). He fulfills the prohibition of deception not merely by observing the law but by being the ontological ground of truth. He also calls his followers to truthfulness: 'Let what you say be simply Yes or No' (Matt 5:37). The kingdom he inaugurates is a community of truth because its head is the truth himself.</p>",
    "12": "<p>A shadow: 'You shall not swear by my name falsely, and so profane the name of your God.' Jesus intensifies this command: 'Do not take an oath at all... let what you say be Yes or No' (Matt 5:34-37). Christ himself speaks with direct authority — 'Truly, truly I say to you' (<em>Amen, amen legō hymin</em>) rather than swearing by YHWH, because he is the one through whom YHWH speaks. He is 'the Amen, the faithful and true witness' (Rev 3:14) — the one whose word needs no oath to validate it, who embodies the trustworthiness the oath-law was designed to protect.</p>",
    "13": "<p>A shadow: 'The wages of a hired worker shall not remain with you all night until the morning.' The immediate payment law is the legal protection for the day-laborer — delay in wages is economic oppression. James 5:4 applies this directly: 'the wages of the laborers who mowed your fields, which you kept back by fraud, are crying out against you, and the cries of the harvesters have reached the ears of the Lord of hosts.' Christ identifies with the oppressed: 'I was hungry and you gave me food... as you did it to one of the least of these my brothers, you did it to me' (Matt 25:35-40). The eschatological judge who hears the cries of the unpaid worker is the same Christ who himself labored for others.</p>",
    "14": "<p>A shadow: 'You shall not curse the deaf or put a stumbling block before the blind, but you shall fear your God.' Christ reverses the exclusion and danger that disability creates: he opens the ears of the deaf (Mark 7:32-35), gives sight to the blind (John 9), calls the crippled and lame to the messianic banquet (Luke 14:13). The law prohibited making the situation of the disabled worse; Christ makes it radically better. The law's protective intent points toward the kingdom where 'the blind receive their sight and the lame walk' (Matt 11:5) — the messianic signs of the new age.</p>",
    "15": "<p>A shadow: 'You shall do no injustice in court. You shall not be partial to the poor or defer to the great, but in righteousness shall you judge your neighbor.' Christ as the righteous judge fulfills this perfectly: 'I can do nothing on my own. As I hear, I judge, and my judgment is just, because I seek not my own will but the will of him who sent me' (John 5:30). He was himself subjected to the very injustice Lev 19:15 forbids — the chief priests and elders 'sought false testimony against Jesus' (Matt 26:59), preferring the great (Roman power, temple establishment) over justice. The unjust trial of Christ exposes the law's violation; his resurrection is the Father's just verdict.</p>",
    "16": "<p>A shadow: 'You shall not go around as a slanderer among your people, and you shall not stand up against the life of your neighbor.' The prohibition against standing by while blood is shed becomes the negative type of Christ's positive act: 'Greater love has no one than this, that someone lay down his life for his friends' (John 15:13). Christ does not stand by passively when his people face death — he intervenes, and the intervention costs him his own life. The law forbids indifference; the gospel shows the ultimate opposite of indifference: a God who enters the danger himself.</p>",
    "17": "<p>A shadow: 'You shall not hate your brother in your heart, but you shall reason frankly with your neighbor, lest you incur sin because of him.' Jesus builds on this: 'If your brother sins against you, go and tell him his fault, between you and him alone' (Matt 18:15) — the private rebuke as the first step of church discipline. Christ himself enacts this principle: he does not destroy sinners silently but calls them by name ('Zacchaeus, hurry and come down'), confronting sin in order to restore. The law requires honest confrontation; Christ models it as the basis of redemptive community.</p>",
    "19": "<p>A shadow: 'You shall keep my statutes. You shall not let your cattle breed with a different kind. You shall not sow your field with two kinds of seed, nor shall you wear a garment of cloth made of two kinds of material.' The <em>kilayim</em> (mixed-kinds) laws preserve created distinctions — each according to its kind, the created order of Gen 1. Paul applies the principle typologically: 'Do not be unequally yoked with unbelievers' (2 Cor 6:14) and develops a theology of the new creation community as distinct from the surrounding world. Christ himself is the one who draws the boundary: 'I have chosen you out of the world, therefore the world hates you' (John 15:19). The new covenant community is, like the holy garment and the unmingled field, a distinct kind.</p>",
    "20": "<p>A shadow: the law concerning a man who lies with a female slave betrothed to another — she shall not be put to death because she was not free; he brings a guilt offering. The gradations of culpability and the provision of atonement even in complex cases of sin point to the principle Christ embodies: no sin is beyond the reach of the guilt offering. Every case, however morally tangled, has a path to atonement. Christ is the guilt offering for the morally complex: 'he who did not know sin was made sin for us' (2 Cor 5:21), covering cases the Levitical system could not fully resolve.</p>",
    "21": "<p>A shadow: 'He shall bring his guilt offering to YHWH, to the entrance of the tent of meeting, a ram for a guilt offering.' The guilty party must come to the sanctuary to find atonement — the sin cannot be dealt with at a distance. Christ comes to where the sinner is: 'the Word became flesh and dwelt among us' (John 1:14). But then he also brings the sinner to where God is: 'through him we have access in one Spirit to the Father' (Eph 2:18). The guilt offering's movement (sinner to sanctuary) is fulfilled in the double movement of the incarnation (God to sinner) and the ascension (sinner to God through Christ).</p>",
    "22": "<p>A shadow: 'And the priest shall make atonement for him before YHWH with the ram of the guilt offering for his sin that he has committed, and he shall be forgiven for the sin that he has committed.' The priestly mediation of forgiveness — the priest acts, the sacrifice is accepted, the sinner is forgiven — is the OT's enacted model of what Christ accomplishes once for all. 'He is the propitiation for our sins, and not for ours only but also for the sins of the whole world' (1 John 2:2). The Levitical priest's mediation was real but limited to individual cases; Christ's mediation is universal and permanent.</p>",
    "23": "<p>A shadow: 'When you come into the land and plant any kind of tree for food, then you shall regard its fruit as forbidden. Three years it shall be forbidden to you; it must not be eaten.' The three-year prohibition before the fruit may be eaten patterns the waiting period before the harvest — appropriate time before the gift is received. The number resonates: Christ's public ministry lasted approximately three years before the fruit of his sacrifice was given. The waiting before the harvest is the shadow of the patience required in the redemptive plan: 'when the fullness of time had come, God sent forth his Son' (Gal 4:4).</p>",
    "24": "<p>A shadow: 'And in the fourth year all its fruit shall be holy, an offering of praise to YHWH.' The fourth-year fruit is consecrated to YHWH — the harvest dedicated before being enjoyed. Christ rises on the first day of the new week, the day of firstfruits — his resurrection-harvest is first consecrated to the Father ('I am ascending to my Father and your Father, to my God and your God', John 20:17) before becoming the basis for the church's new life. The fourth-year consecration points to the resurrection dedication: Christ offered to the Father before being given to the church.</p>",
    "25": "<p>A shadow: 'And in the fifth year you may eat of its fruit, to increase its yield for you.' Only after dedication may the full harvest be enjoyed. Christ's gift to the church — the Spirit, the fullness of new covenant life — comes only after his consecration to the Father: 'Nevertheless, I tell you the truth: it is to your advantage that I go away, for if I do not go away, the Helper will not come to you' (John 16:7). The fifth-year abundance follows the fourth-year dedication; the Spirit's abundance in the church follows Christ's ascension and intercession at the Father's right hand.</p>",
    "26": "<p>A shadow: 'You shall not eat any flesh with blood in it. You shall not interpret omens or tell fortunes.' The prohibition of divination is the law's witness that the future belongs to YHWH alone. Christ fulfills this by being the one through whom God speaks his final word: 'Long ago, at many times and in many ways, God spoke to our fathers by the prophets, but in these last days he has spoken to us by his Son' (Heb 1:1-2). The need for oracles and omens ends when the Word himself comes. Christ also expels the unclean spirits that drove the divination practices of the ancient world: 'the prince of this world has been judged' (John 16:11).</p>",
    "27": "<p>A shadow: 'You shall not round off the hair on your temples or mar the edges of your beard.' These prohibitions ban the hair-cutting rites associated with pagan mourning practices — the body was not to be ritually disfigured as if death had ultimate power. Christ transforms mourning: 'Blessed are those who mourn, for they shall be comforted' (Matt 5:4). His resurrection means death no longer has the last word, and the mourning-rites that expressed hopeless grief before pagan gods are replaced by the hope of the resurrection. 'I am the resurrection and the life' (John 11:25) — the one in whose presence pagan death-mourning is rendered obsolete.</p>",
    "28": "<p>A shadow: 'You shall not make any cuts on your body for the dead or tattoo yourselves.' The prohibition against marking the body for the dead has an implicit NT counterpart: 'Do you not know that your body is a temple of the Holy Spirit within you, whom you have from God? You are not your own, for you were bought with a price' (1 Cor 6:19-20). The body belongs to God — in the OT because YHWH is Creator, in the NT because Christ's blood purchased it. The body is not a surface for ritual marking in the service of the dead; it is the Spirit's dwelling, purchased by the living Christ.</p>",
    "29": "<p>A shadow: 'Do not profane your daughter by making her a prostitute, lest the land fall into prostitution and the land become full of depravity.' The prohibition of sexual exploitation protects the daughter's honor. In Christ's fulfillment, the church is the daughter/bride who must be kept pure: 'I betrothed you to one husband, to present you as a pure virgin to Christ' (2 Cor 11:2). Christ 'gave himself up for her, that he might sanctify her, having cleansed her by the washing of water with the word, so that he might present the church to himself in splendor, without spot or wrinkle' (Eph 5:25-27). The law protects the daughter from prostitution; Christ dies to purify the bride.</p>",
    "30": "<p>A shadow: 'You shall keep my sabbaths and reverence my sanctuary: I am YHWH.' The sabbath and sanctuary command is fulfilled and transformed in Christ. Christ is 'Lord of the Sabbath' (Matt 12:8), the one who gives true rest: 'Come to me, all who labor and are heavy laden, and I will give you rest' (Matt 11:28). The sanctuary (temple) is his body (John 2:21) and then the community of his Spirit (1 Cor 3:16). The reverence due the physical sanctuary is now the reverence due the risen Christ who is present among his gathered people: 'where two or three are gathered in my name, there am I among them' (Matt 18:20).</p>",
    "31": "<p>A shadow: 'Do not turn to mediums or necromancers; do not seek them out, and so make yourselves unclean by them.' The prohibition of consulting the dead for guidance is abolished in Christ, who is the one mediator: 'there is one God, and there is one mediator between God and men, the man Christ Jesus' (1 Tim 2:5). All spiritual guidance comes through him and by his Spirit: 'When the Spirit of truth comes, he will guide you into all the truth' (John 16:13). The Witch of Endor consulted a dead spirit in despair (1 Sam 28); Christ himself is the living Lord who speaks to his people and gives them no cause to seek the dead.</p>",
    "32": "<p>A shadow: 'You shall stand up before the gray head and honor the face of an old man, and you shall fear your God.' The honor of the aged reflects YHWH's own eternity — wisdom accumulated over time reflects the character of the God who is from everlasting. Christ is the one in whom all wisdom and knowledge are hidden (Col 2:3) — not wisdom accumulated over time but wisdom that is eternal: 'before Abraham was, I am' (John 8:58). He is 'the Ancient of Days' (Dan 7:9-13) in human form, the one before whom every knee will bow (Phil 2:10) — the ultimate elder deserving honor.</p>",
    "33": "<p>A shadow: 'When a stranger sojourns with you in your land, you shall not do him wrong.' The protection of the alien is the ethical application of Israel's own experience: 'you were aliens in the land of Egypt.' Christ came to the alienated and the outsider as the one who was himself an outsider: 'the Word... came to his own, and his own people did not receive him' (John 1:11). The alien-protection law finds its fullest expression in the Gentile mission: 'the Gentiles, who did not pursue righteousness, have attained it' (Rom 9:30). The stranger who sojourns is now welcomed into the covenant family through Christ.</p>",
    "34": "<p>A direct quotation: 'You shall treat the stranger who sojourns with you as the native among you, and you shall love him as yourself, for you were strangers in the land of Egypt.' This verse extends the neighbor-love command of v. 18 explicitly to the alien — the love-your-neighbor command is not restricted to coethnics. Paul builds the entire Gentile-mission theology on this expansion: 'there is no distinction between Jew and Greek; for the same Lord is Lord of all' (Rom 10:12). Christ's death removes 'the dividing wall of hostility' (Eph 2:14) — the once-alien Gentiles are 'no longer strangers and aliens, but fellow citizens with the saints' (Eph 2:19).</p>",
    "35": "<p>A shadow: 'You shall do no wrong in judgment, in measures of length or weight or quantity.' Honest commercial dealings reflect YHWH's justice — a just God demands just measures from his people. Christ as the coming judge who will evaluate every weight and measure: 'with the judgment you pronounce you will be judged, and with the measure you use it will be measured to you' (Matt 7:2). The eschatological judgment (Rev 6:5-6 — the scales of judgment) renders every dishonest commercial transaction accountable. The just Judge who will weigh all things is the one whose own life was weighed and found to be of infinite worth.</p>",
    "36": "<p>A shadow: 'You shall have just balances, just weights, a just ephah, and a just hin.' The specific instruments of measurement — the stone weights, the dry measure, the liquid measure — are all subject to YHWH's justice. Christ is the 'faithful and true witness' (Rev 3:14) and the 'cornerstone' (Eph 2:20) — the standard by which all things are measured. The church, called to honest measurement in commerce, is also called to 'speaking the truth in love' (Eph 4:15) — measuring all things by the standard of the one who is truth itself. 'Test everything; hold fast what is good' (1 Thess 5:21).</p>",
    "37": "<p>A summary: 'You shall observe all my statutes and all my rules and do them: I am YHWH.' The Holiness Code closes with the inclusive summary — all the laws, both civil and religious, point to YHWH's character. Christ's declaration 'Do not think that I have come to abolish the Law or the Prophets; I have not come to abolish them but to fulfill them' (Matt 5:17) is the NT's direct response to Lev 19:37. He fulfills by embodying: the love-of-neighbor, the honest weights, the care for the alien, the purity of worship, the justice of judgment — Christ is the living summary of every statute in chapter 19.</p>"
  },
  "20": {
    "1": "<p>A literary frame: YHWH addresses Moses with the penalty-provisions for the Holiness Code violations — the sanctions that enforce the statutes of chapter 19. The chapter opens with Molech-worship, the worst apostasy (child sacrifice). The escalating severity of the penalties (death, cutting off, childlessness) mirrors the gravity of covenant violation. Christ came not to set aside these moral boundaries but to fulfill the covenant demands himself: 'Christ redeemed us from the curse of the law by becoming a curse for us' (Gal 3:13). The penalties of Leviticus 20 are the shadow of the curse Christ bore.</p>",
    "2": "<p>A shadow: 'Any person — whether Israelite or foreigner... who gives any of his children to Molech shall surely be put to death.' Molech-worship demanded child sacrifice — the darkest of ancient Near Eastern practices, offering a child's life to secure divine favor. The antithesis is the gospel: God does not demand the sacrifice of children — he gives his own Son: 'For God so loved the world, that he gave his only Son' (John 3:16). The Molech-worshipper sacrifices his child to gain life; God sacrifices his Son to give life to others. The law's harshest penalty guards the boundary that the gospel crosses from the opposite side.</p>",
    "3": "<p>A shadow: 'I will set my face against that man and will cut him off from among his people, because he has given one of his children to Molech, so as to make my sanctuary unclean and to profane my holy name.' The divine judgment ('I will set my face against') is the language of covenant wrath. Christ, bearing the covenant curse at the cross, faces the precise opposite: God does not set his face against Christ in permanent rejection but vindicates him in the resurrection. 'My God, my God, why have you forsaken me?' (Matt 27:46) is the temporary moment of forsakenness that secures the permanent 'I will never leave you nor forsake you' (Heb 13:5) for those united to Christ.</p>",
    "4": "<p>A shadow: 'If the people of the land close their eyes to what that man does when he gives his children to Molech, and do not put him to death, then I will set my face against that man and his family.' The community bears responsibility for enforcing covenant standards — silence in the face of apostasy is complicity. Christ confronts this in his prophetic ministry: 'Woe to you, scribes and Pharisees, hypocrites! For you shut the kingdom of heaven in people's faces' (Matt 23:13). The church is called not to 'close its eyes' to covenant violation but to speak the truth in love (Eph 4:15), as Christ did without flinching.</p>",
    "5": "<p>A shadow: 'I will set my face against that man and his family and will cut off from among their people him and all who follow him in whoring after Molech.' The judgment extends to those who follow apostasy, not merely the instigator. Paul warns: 'Do not be deceived: bad company ruins good morals' (1 Cor 15:33). Christ separates the gathered from the scattered: 'Whoever is not with me is against me, and whoever does not gather with me scatters' (Matt 12:30). The cutting-off judgment points to the final separation Christ describes: 'I never knew you; depart from me, you workers of lawlessness' (Matt 7:23).</p>",
    "6": "<p>A shadow: 'If a person turns to mediums and necromancers, whoring after them, I will set my face against that person and will cut him off from among his people.' The consulting of the dead for guidance is the spiritual adultery that the law calls 'whoring' (<em>zinnah</em>). Christ is the living Lord who renders all necromancy obsolete: 'I am the first and the last, and the living one. I died, and behold I am alive forevermore, and I have the keys of Death and Hades' (Rev 1:17-18). The one who holds the keys of death is the only legitimate guide through death — seeking the dead for guidance is unnecessary when the risen Christ speaks by his Spirit.</p>",
    "7": "<p>A direct quotation type: 'Consecrate yourselves, therefore, and be holy, for I am YHWH your God.' Peter quotes this verse alongside Lev 19:2 in 1 Pet 1:15-16. The consecration-call is fulfilled in Christ's high-priestly prayer: 'Sanctify them in the truth; your word is truth. As you sent me into the world, so I have sent them into the world. And for their sake I consecrate myself, that they also may be sanctified in truth' (John 17:17-19). Christ consecrates himself so that his people may be consecrated — the source of all holiness is not human effort but union with the Holy One who has set himself apart for our sake.</p>",
    "8": "<p>A direct revelation: 'Keep my statutes and do them; I am YHWH who sanctifies you.' The divine self-identification as the one who sanctifies — <em>YHWH mekadishchem</em>, 'YHWH your sanctifier' — is one of the most important covenant titles in Leviticus. Paul applies the sanctification title to Christ: 'Jesus Christ, who became to us wisdom from God, righteousness and sanctification and redemption' (1 Cor 1:30). Christ is YHWH-who-sanctifies in person — the eternal 'I am YHWH' has a name: Jesus, who sanctifies 'those who draw near to God through him' (Heb 7:25).</p>",
    "9": "<p>A shadow: 'For anyone who curses his father or his mother shall surely be put to death.' The fifth commandment carries a death penalty for its violation at the extreme — the covenantal severity mirrors the seriousness of the parent-honor obligation. Christ himself bore 'the curse of the law' (Gal 3:13) in his death — not for his own violation (he fulfilled all the commandments) but for ours. The severity of Lev 20:9 is the legal backdrop for the NT's theology of Christ as the substitute who bore the death-penalty on behalf of covenant-breakers. 'Christ redeemed us from the curse of the law by becoming a curse for us — for it is written, Cursed is everyone who is hanged on a tree' (Gal 3:13).</p>",
    "10": "<p>A shadow: 'If a man commits adultery with the wife of his neighbor, both the adulterer and the adulteress shall surely be put to death.' When the scribes and Pharisees brought a woman caught in adultery to Jesus (John 8:3-11), they invoked Lev 20:10 — the law requiring death. Jesus's response — 'Let him who is without sin among you be the first to throw a stone' (John 8:7) — does not abolish the law but exposes that no accuser can stand before it either. He then forgives: 'Neither do I condemn you; go, and from now on sin no more.' Christ fulfills the law's demand by bearing it himself, and transforms its enforcement from condemnation to the call to repentance.</p>",
    "11": "<p>A shadow: incest (father's wife) carries the death penalty — 'their blood is upon them.' The escalating sexual holiness laws define the purity of the covenant community. Paul confronts a case in Corinth (1 Cor 5:1-5) — a man living with his father's wife — and quotes Lev 20:11 implicitly by demanding severe discipline: 'hand this man over to Satan for the destruction of the flesh, so that his spirit may be saved in the day of the Lord.' The church, as the new Israel, maintains the covenant purity boundaries, but now the goal is restoration, not merely punishment — the discipline serves the ultimate hope of redemption.</p>",
    "12": "<p>A shadow: 'If a man lies with his daughter-in-law, both of them shall surely be put to death.' The death penalties for incest establish the absolute boundaries of the family covenant-structure. Christ expands the family covenant while maintaining its purity: 'Whoever does the will of God, he is my brother and sister and mother' (Mark 3:35). The kingdom family is constituted by covenant fidelity to God, not natural descent — and it maintains, in the Spirit, the same purity that the Levitical law mandated externally.</p>",
    "13": "<p>A shadow: the death penalty for male homosexual intercourse is one of the Levitical boundaries Paul invokes in Romans 1:24-27 as evidence of the suppression of created order. Paul's point in Romans 1 is that the escalating moral disorder described there — including the abandonment of natural relations — is God's judgment (giving them over) upon a world that refuses to honor God. Christ's redemption reverses this disorder: 'such were some of you. But you were washed, you were sanctified, you were justified in the name of the Lord Jesus Christ and by the Spirit of our God' (1 Cor 6:11). The law names the disorder; the gospel names the transformation.</p>",
    "14": "<p>A shadow: the prohibition of taking both a woman and her mother, with a death by fire. The sexual ethics of Leviticus 20 protect the integrity of the family unit — the basic building block of the covenant community. Christ presents himself as the one who ultimately unifies the family in a deeper sense: 'everyone who has left houses or brothers or sisters or father or mother or children or lands, for my name's sake, will receive a hundredfold and will inherit eternal life' (Matt 19:29). The kingdom family supersedes the biological family without abolishing it.</p>",
    "15": "<p>A shadow: bestiality — death for both man and animal. The death penalties in Leviticus 20 together constitute the covenant community's absolute boundary — the 'not this' by which the holy community is defined. Christ defines his people positively: 'my sheep hear my voice' (John 10:27). The laws of Leviticus 20 are the negative boundary-markers; the gospel is the positive call that brings people into the covenant community — called, washed, and renewed to reflect YHWH's holiness in positive obedience.</p>",
    "16": "<p>A shadow: the same death penalty applies to the woman in the case of Lev 20:16. The equal culpability of both parties reflects YHWH's impartial justice — no double standard. Christ's impartiality in judgment: 'God shows no partiality' (Rom 2:11). Paul applies this to the gospel: 'there is neither male nor female, for you are all one in Christ Jesus' (Gal 3:28). The covenant boundaries apply equally; the covenant grace is also equally available — 'there is no distinction: for all have sinned and fall short of the glory of God, and are justified by his grace as a gift' (Rom 3:22-24).</p>",
    "17": "<p>A shadow: incest with a sister — 'a disgrace, and they shall be cut off in the sight of the children of their people.' The concept of 'cutting off' (<em>karet</em>) from the people is the covenant's internal exile — the offender is separated from YHWH's community and its blessings. Christ reverses <em>karet</em> by suffering the ultimate cutting off — 'he was cut off from the land of the living, stricken for the transgression of my people' (Isa 53:8). The exile of the covenant-breaker is borne by the covenant-keeper, so that those who deserve cutting off may be grafted in (Rom 11:17-24).</p>",
    "18": "<p>A shadow: the prohibition of intercourse during menstruation. The purity laws create a structure of separation and reunion — the monthly cycle of distance and return mirrors the broader OT pattern of exile and restoration, judgment and reconciliation. Christ abolishes the separation: the woman with the flow of blood who touched the hem of his garment (Mark 5:25-34) — ritually unclean, excluded from full temple access — is healed instantly, and Jesus calls her 'daughter.' The one who made her unclean touches him and makes him, as it were, responsible for her condition; instead, his holiness flows out and cleanses her.</p>",
    "19": "<p>A shadow: the prohibitions against intercourse with an aunt. The increasingly specific incest prohibitions in Leviticus 20 enumerate the covenant family's integrity. These laws gave Israel's family structure its distinctive covenant purity, setting it apart from surrounding cultures. The church inherits a transformed version of this family purity — not biological relations but spiritual ones. The community that is 'built up as a spiritual house' (1 Pet 2:5) maintains its integrity through Christ, 'the cornerstone' (1 Pet 2:6) who defines the shape of the covenant household.</p>",
    "20": "<p>A shadow: 'If a man lies with his uncle's wife, he has uncovered his uncle's nakedness; they shall bear their sin; they shall die childless.' The consequence of 'dying childless' resonates with the Abrahamic covenant: the promise was carried through offspring, and childlessness was the covenant curse. Christ reverses the spiritual childlessness of sin: 'I will give him... an everlasting name that shall not be cut off' (Isa 56:5). Through Christ, those who were spiritually cut off from the covenant become children of God: 'to all who received him, who believed in his name, he gave the right to become children of God' (John 1:12).</p>",
    "21": "<p>A shadow: 'If a man takes his brother's wife, it is impurity.' John the Baptist rebuked Herod for exactly this violation — 'It is not lawful for you to have your brother's wife' (Mark 6:18). His fidelity to Lev 20:21 cost him his head (Mark 6:27). The Baptist's martyrdom for covenant-truth is the type of Christ's own death: both are killed by political-religious collusion for speaking uncomfortable truth. 'A servant is not greater than his master. If they persecuted me, they will also persecute you' (John 15:20). The prophet who dies for covenant fidelity anticipates the Prophet who dies for covenant fulfillment.</p>",
    "22": "<p>A shadow: 'You shall therefore keep all my statutes and all my rules and do them, that the land where I am bringing you to live may not vomit you out.' The land of Canaan is the type of the kingdom of God — and the kingdom can expel the unfaithful. Christ teaches this with the parable of the wedding garment (Matt 22:11-13): entry is by grace, but complacent covenant-violation leads to exclusion. 'Every branch in me that does not bear fruit he takes away' (John 15:2). The promised land's threat of vomiting up the disobedient points to the kingdom's eschatological seriousness.</p>",
    "23": "<p>A shadow: 'And you shall not walk in the customs of the nation that I am driving out before you, for they did all these things, and therefore I detested them.' The ethical distinctiveness of Israel from the surrounding nations is grounded in YHWH's own standard — not cultural preference but divine character. Christ calls his people to the same counter-cultural distinctiveness: 'You are the light of the world' (Matt 5:14); 'Do not be conformed to this world' (Rom 12:2). The holiness-distance from surrounding culture that Leviticus legislated is now the Spirit-formed character of the new covenant community.</p>",
    "24": "<p>A shadow: 'I am YHWH your God, who has separated you from the peoples... to be mine.' The election-separation formula — 'I have set you apart' — is the covenant's foundational claim on Israel. Paul applies it to the church: 'But you are a chosen race, a royal priesthood, a holy nation, a people for his own possession' (1 Pet 2:9, quoting Exod 19:6; also Deut 7:6). Christ is the one through whom this election-separation reaches the Gentiles — 'you once were not a people, but now you are God's people' (1 Pet 2:10). The Lord who separated Israel from the nations has in Christ separated a new covenant people from every nation.</p>",
    "25": "<p>A shadow: 'You shall therefore separate the clean beast from the unclean, and the unclean bird from the clean.' The clean/unclean animal distinction, established in Lev 11, is here applied in the broader context of Israel's separation from the nations. Peter's vision in Acts 10:9-16 — 'What God has made clean, do not call common' — directly abrogates this distinction. The clean/unclean food law was the physical enactment of the Jew/Gentile distinction; when Christ declares 'all foods clean' (Mark 7:19), the ethnic-boundary significance of the law is abolished in principle. The Gentile mission flows directly from this fulfillment.</p>",
    "26": "<p>A direct revelation: 'You shall be holy to me, for I YHWH am holy and have separated you from the peoples, that you should be mine.' This is the fullest statement of the Holiness Code's purpose: holiness is not a legal achievement but a relational status — set apart to belong to YHWH. In Christ, the belonging is made explicit in its fullest form: 'you are not your own, for you were bought with a price' (1 Cor 6:19-20). The church belongs to Christ as Israel belonged to YHWH — called out (<em>ekklesia</em>), purchased, and set apart. The 'you should be mine' of Lev 20:26 echoes in the covenant formula of Revelation: 'They will be his people, and God himself will be with them as their God' (Rev 21:3).</p>",
    "27": "<p>A shadow: 'A man or a woman who is a medium or a necromancer shall surely be put to death.' The death penalty for false spiritual mediation closes the chapter — the law protects the exclusive channel of divine communication. Christ as the sole mediator makes all other mediation unnecessary and therefore illegitimate: 'there is one mediator between God and men, the man Christ Jesus, who gave himself as a ransom for all' (1 Tim 2:5-6). The finality of the death penalty for false mediation in Lev 20:27 corresponds to the NT's insistence that 'there is salvation in no one else, for there is no other name under heaven given among men by which we must be saved' (Acts 4:12).</p>"
  },
  "21": {
    "1": "<p>A shadow: the law of priestly defilement opens the chapter — priests are held to a higher standard regarding corpse-contact than ordinary Israelites. The entire chapter is Leviticus' most detailed treatment of the Aaronic high-priesthood's unique holiness requirements. Hebrews reads Leviticus 21 as the detailed typological preparation for understanding Christ as the unique high priest: 'For it was indeed fitting that we should have such a high priest, holy, innocent, unstained, separated from sinners, and exalted above the heavens' (Heb 7:26). Every specific requirement of ch. 21 finds its antitype in Christ's perfect high-priestly holiness.</p>",
    "2": "<p>A shadow: the priest may defile himself for close relatives — mother, father, son, daughter, brother. Even the strict purity requirements have a provision for intimate grief — the priest is not forbidden all mourning, only inappropriate mourning. Christ himself wept at Lazarus's tomb (John 11:35) — the incarnate high priest was not immune to human grief. 'For we do not have a high priest who is unable to sympathize with our weaknesses, but one who in every respect has been tempted as we are, yet without sinning' (Heb 4:15). The Levitical priest's limited mourning-right points to Christ's genuine solidarity with human grief.</p>",
    "3": "<p>A shadow: the unmarried sister who has no husband may be mourned. The provision for the vulnerable dependent — the unmarried sister — within the priestly mourning-exception reflects the law's care for those without a husband's protection. Christ as the husband and protector of the vulnerable: 'Husbands, love your wives, as Christ loved the church and gave himself up for her' (Eph 5:25). The church as the unmarried sister who belongs to Christ's household — not yet married at the parousia but under his protection and heading toward the wedding feast of the Lamb (Rev 19:7-9).</p>",
    "4": "<p>A shadow: 'He shall not defile himself as a husband among his people and so profane himself.' The priest's distinction from ordinary mourning practices marks his unique consecration — his identity as a servant of YHWH overrides the ordinary claims of social custom. Christ's identity overrides every other claim: 'Who is my mother, and who are my brothers?... whoever does the will of my Father in heaven is my brother and sister and mother' (Matt 12:48-50). The high priest's singular consecration to YHWH's service is the type of Christ's total dedication to the Father's will: 'My food is to do the will of him who sent me and to accomplish his work' (John 4:34).</p>",
    "5": "<p>A shadow: 'They shall not make bald patches on their heads, nor shave off the edges of their beards, nor make any cuts on their body.' These are the pagan mourning-rites that the priests are explicitly forbidden — the body-marking rituals that treated death as the ultimate power. Christ transforms grief with hope: 'I am the resurrection and the life. Whoever believes in me, though he die, yet shall he live' (John 11:25). The priest who was forbidden to mark his body with pagan death-mourning is the type of the resurrection community — 'We do not want you to be uninformed... about those who are asleep, that you may not grieve as others do who have no hope' (1 Thess 4:13).</p>",
    "6": "<p>A direct revelation: 'They shall be holy to their God and not profane the name of their God. For they offer the LORD's food offerings, the bread of their God; therefore they shall be holy.' The priests are holy because they handle holy things — the bread/food offerings of YHWH. Christ identifies himself as 'the bread of God... who comes down from heaven and gives life to the world' (John 6:33) — he is not merely the one who presents the bread but is himself the bread. The Levitical priest offers bread to God; Christ offers himself as the bread from God. The sacrifice and the sacrificer are one in Christ.</p>",
    "7": "<p>A shadow: 'They shall not marry a prostitute or a woman who has been defiled, neither shall they marry a woman divorced from her husband.' The priestly marriage requirements protect the covenant purity of the priestly line. Christ claims the church as his pure bride: 'I betrothed you to one husband, to present you as a pure virgin to Christ' (2 Cor 11:2). The church has indeed been 'defiled' by sin before Christ — 'we too once lived in the passions of our flesh' (Eph 2:3) — yet Christ gives himself up for her 'so that he might present the church to himself in splendor, without spot or wrinkle' (Eph 5:27). The priestly marriage law is the type of Christ's transforming love for an impure bride he makes pure.</p>",
    "8": "<p>A shadow: 'You shall sanctify him, for he offers the bread of your God. He shall be holy to you, for I, the LORD, who sanctify you, am holy.' The community's responsibility to recognize and honor the priest's holiness — 'you shall sanctify him' — mirrors the church's calling to honor Christ as holy. Peter applies the verb-of-sanctifying to Christ himself: 'In your hearts honor Christ the Lord as holy' (1 Pet 3:15, the same root as <em>hagiazō</em>, to sanctify). YHWH who sanctifies Israel (Lev 20:8) is the same one who sanctifies Christ's people through him — 'both the one who makes people holy and those who are made holy are of the same family' (Heb 2:11).</p>",
    "9": "<p>A shadow: 'And the daughter of any priest, if she profanes herself by whoring, profanes her father; she shall be burned with fire.' The highest penalty for the priest's daughter who prostitutes herself reflects how the priest's family bears the priest's holiness. Christ's people — his 'children' in the family of God — are called to holiness that reflects the Father's holiness: 'As obedient children, do not be conformed to the passions of your former ignorance, but as he who called you is holy, you also be holy in all your conduct' (1 Pet 1:14-15). The honor of the family name is at stake in how Christ's people live.</p>",
    "10": "<p>A direct type: 'The priest who is chief among his brothers, on whose head the anointing oil was poured and who has been consecrated to wear the garments, shall not let the hair of his head hang loose nor tear his clothes.' The high priest's distinctive holiness — anointing oil poured on his head — is the precise type of Christ's anointing. Jesus at the Jordan: 'the heavens were opened to him, and he saw the Spirit of God descending like a dove and coming to rest on him' (Matt 3:16). <em>Mashiach</em> (anointed one) and <em>Christos</em> (anointed) are the same title. The Levitical high priest with oil on his head is the enacted preview of the Messiah with the Spirit upon him.</p>",
    "11": "<p>A shadow: 'He shall not go in to any dead bodies nor make himself unclean, even for his father or for his mother.' The high priest's absolute prohibition of corpse-contact distinguishes him from all other priests — not even the closest family bereavement can interrupt his sanctuary service. Yet Christ enters death voluntarily: 'he tasted death for everyone' (Heb 2:9). The Levitical high priest's extreme separation from death is the shadow of Christ's extreme conquest of death — he does not merely avoid the dead but descends into death and rises from it, 'having the keys of Death and Hades' (Rev 1:18). He is not unclean by death; death is undone by him.</p>",
    "12": "<p>A shadow: 'He shall not go out of the sanctuary, lest he profane the sanctuary of his God, for the consecration of the anointing oil of his God is on him.' The high priest's constant presence in the sanctuary — he does not leave the holy space — is the type of Christ's perpetual heavenly intercession. 'He always lives to make intercession for them' (Heb 7:25). The Levitical high priest who cannot leave the sanctuary provides the image; Christ as the risen high priest who 'passed through the heavens' (Heb 4:14) and now stands permanently in God's presence for his people is the reality. The consecration of the anointing oil demands constant sanctuary service; the consecration of the Spirit demands Christ's perpetual intercession.</p>",
    "13": "<p>A shadow: 'And he shall take a wife in her virginity.' The high priest's marriage requirement — virgin from his own people — is the type of Christ's claim on the church. Paul: 'I betrothed you to one husband, to present you as a pure virgin to Christ' (2 Cor 11:2). The church is the virgin bride, and Christ is the bridegroom who claims her exclusively. The high priest cannot marry a widow, divorced woman, or prostitute — only a virgin. The church's purity in Christ is not natural but restored: 'you were washed, you were sanctified, you were justified in the name of the Lord Jesus Christ' (1 Cor 6:11). The high priest's virgin-bride requirement points to Christ's transforming love that makes his bride virgin.</p>",
    "14": "<p>A shadow: 'A widow, or a divorced woman, or a woman who has been defiled, or a prostitute — these he shall not marry.' The list of disqualified women for high-priestly marriage is the negative by which the positive is defined: the high priest seeks a pure virgin. Christ 'loved the church and gave himself up for her, that he might sanctify her... so that he might present the church to himself in splendor, without spot or wrinkle or any such thing, that she might be holy and without blemish' (Eph 5:25-27). What the law required the high priest to marry (a pure virgin), Christ creates in his church by his atoning work — the bride who was defiled is made pure.</p>",
    "15": "<p>A shadow: 'that he may not profane his offspring among his people.' The high priest's marriage purity protects the holiness of the priestly line — the offspring must be fit to serve in the sanctuary. Christ's 'offspring' — 'his seed' (Isa 53:10) — are those who believe in him and are born again by the Spirit: 'You are a chosen race, a royal priesthood, a holy nation' (1 Pet 2:9). The new covenant priesthood is constituted by the purity of the high priest's own sacrifice — not the purity of his marriage but the perfection of his offering. Those born from his sacrifice are qualified to be a 'holy priesthood, to offer spiritual sacrifices acceptable to God through Jesus Christ' (1 Pet 2:5).</p>",
    "16": "<p>A literary frame: YHWH addresses Moses with the priestly physical-defect laws — the list of conditions that disqualify a priest from altar service. The chapter's second half enumerates the disqualifications in detail. By contrast, Christ is the perfect high priest who embodies every positive quality: 'For it was indeed fitting that we should have such a high priest, holy, innocent, unstained, separated from sinners, and exalted above the heavens' (Heb 7:26). The Levitical disqualification list paints in negative space the portrait of the one who has no defect, no blemish, no impairment — the perfect high priest.</p>",
    "17": "<p>A shadow: 'None of your offspring throughout their generations who has a blemish may approach to offer the bread of his God.' The blemish-prohibition for altar service is the type of the unblemished sacrifice required. Peter applies it directly to Christ's sacrifice: 'you were ransomed... with the precious blood of Christ, like that of a lamb without blemish or spot' (1 Pet 1:18-19). The priest without a blemish must offer the sacrifice; in Christ, the priest and the sacrifice are the same — the unblemished priest offers his own unblemished life. The Levitical law required the priest to be whole; Christ was the only truly whole person to ever live, and he offered himself.</p>",
    "18": "<p>A shadow: the list of disqualifying conditions — blind, lame, mutilated face, limb too long. These physical conditions, though they disqualify from altar service, do not exclude from the priestly family (v. 22). Christ both fulfills the altar-service qualification (no defect) and inverts the exclusion: 'the blind receive their sight and the lame walk' (Matt 11:5). Those very persons excluded from the sanctuary in Lev 21 come to Jesus, the true temple: 'And the blind and the lame came to him in the temple, and he healed them' (Matt 21:14). The one who alone qualifies for the true altar service also removes every disqualification from those who come to him.</p>",
    "19": "<p>A shadow: 'a man who has an injured foot or an injured hand' — excluded from altar service. Yet Christ's own risen body bears the marks of his wounds: 'Put your finger here, and see my hands' (John 20:27). The risen high priest carries the marks of his suffering into the heavenly sanctuary — not as disqualifying blemishes but as the everlasting evidence of his completed sacrifice. 'It was fitting that he, for whom and by whom all things exist, in bringing many sons to glory, should make the founder of their salvation perfect through suffering' (Heb 2:10). The wounds of Christ are the credentials of the perfect high priest.</p>",
    "20": "<p>A shadow: the hunchback, the dwarf, the man with a defect in his sight, the man with eczema or scabs, the man with crushed testicles — all excluded from altar service. The comprehensiveness of the disqualification list — no physical imperfection was overlooked — creates by negative definition the portrait of perfect physical wholeness. Christ the perfect offering: 'He had no form or majesty that we should look at him, and no beauty that we should desire him' (Isa 53:2) — his outward appearance did not commend him, yet he was inwardly perfect. The Levitical list focuses on outer wholeness; Christ's perfection is the inner moral and spiritual wholeness that matters before God.</p>",
    "21": "<p>A shadow: 'No man of the offspring of Aaron the priest who has a blemish shall come near to offer the LORD's food offerings; since he has a blemish, he shall not come near to offer the bread of his God.' The disqualification is absolute for the offering — no blemished man at the altar. Christ is the one who passes this test absolutely: his offering is accepted because he himself is without defect. 'For by a single offering he has perfected for all time those who are being sanctified' (Heb 10:14). The single unblemished offering accomplishes what the law's perfect-offering requirement was pointing toward — not repeated imperfect sacrifices but one perfect sacrifice, once for all.</p>",
    "22": "<p>A shadow: 'He may eat the bread of his God, both of the most holy and of the holy things, but he shall not go through the veil or approach the altar, because he has a blemish.' The blemished priest may eat the holy food but cannot approach the altar — partial inclusion, not total exclusion. Christ tears the veil (Matt 27:51) — the barrier that limited access is removed. Now all who come to Christ have full access, not partial: 'we have confidence to enter the holy places by the blood of Jesus, by the new and living way that he opened for us through the curtain' (Heb 10:19-20). What the blemished priest was denied — full sanctuary access — is now given to all through Christ's blood.</p>",
    "23": "<p>A shadow: 'that he may not profane my sanctuaries, for I am the LORD who sanctifies them.' The word 'sanctuaries' (plural: the altar and the inner sanctuary) are YHWH's own — he is their sanctifier, not the priests. Christ as the one who sanctifies both the people and the sanctuary: 'both he who sanctifies and those who are sanctified are all of one origin. That is why he is not ashamed to call them brothers' (Heb 2:11). The holy sanctuaries of Leviticus point toward the heavenly sanctuary where Christ 'entered, not into holy places made with hands... but into heaven itself, now to appear in the presence of God on our behalf' (Heb 9:24).</p>",
    "24": "<p>A summary: 'So Moses spoke to Aaron and to his sons and to all the people of Israel.' The teaching moment — Moses transmits the laws of priestly holiness to Aaron, his sons, and all Israel. Christ as the teacher who surpasses Moses: 'The law was given through Moses; grace and truth came through Jesus Christ' (John 1:17). Moses mediates the law of priestly qualification; Christ himself is the qualification. 'For the law appoints men in their weakness as high priests, but the word of the oath, which came later than the law, appoints a Son who has been made perfect forever' (Heb 7:28). The Levitical teaching points to the living Teacher who embodies all it requires.</p>"
  }
}

def main():
    c = load_comm('mkt-christ', 'leviticus')
    merge_comm(c, CHRIST)
    save_comm('mkt-christ', 'leviticus', c)
    print('leviticus mkt-christ: ch 19-21 written')

if __name__ == '__main__':
    main()
